from aws_lambda_powertools.utilities.idempotency import idempotent from aws_lambda_powertools.utilities.idempotency import DynamoDBPersistenceLayer
persistence_layer = DynamoDBPersistenceLayer(table_name='IdempotencyTable')
@idempotent(persistence_store=persistence_layer) def handler(event, context): # Safe from duplicate executions — same event_id returns cached result order = event['order'] charge_payment(order['amount']) send_confirmation(order['email']) save_order(order)
